// This file must be served from the SITE ROOT (not a subfolder) —
// https://she-rises.vercel.app/firebase-messaging-sw.js — for push
// notifications to work when the dashboard tab isn't open/focused.
//
// Firebase config comes from config.js (generated by scripts/build-config.js
// from your .env.local / Vercel env vars) — nothing hardcoded here. config.js
// sets these via `self.X = ...` rather than `window.X = ...` specifically so
// it works in this service worker scope too (there's no `window` here).

importScripts('/config.js');
importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/10.12.0/firebase-messaging-compat.js');

if (self.FIREBASE_CONFIG) {
  firebase.initializeApp(self.FIREBASE_CONFIG);

  const messaging = firebase.messaging();

  messaging.onBackgroundMessage((payload) => {
    const { title, body } = payload.notification || {};
    self.registration.showNotification(title || 'She Rises', {
      body: body || 'You have a new case assigned.',
      icon: '/favicon.png',
    });
  });
} else {
  console.warn('Firebase not configured yet (missing env vars) — background push notifications disabled.');
}